INSERT INTO exercises (
  exercisedb_id, name, name_es,
  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'trmte8s',
  'band shrug',
  'Band Shrug',
  'https://static.exercisedb.dev/media/trmte8s.gif',
  'neck',
  'band',
  'traps',
  ARRAY['shoulders']::text[],
  ARRAY['Paso 1: párate con los pies al ancho de los hombros and place the band under tus pies, holding the ends with tus manos.', 'Paso 2: Keep tus brazos straight and relaxed, and let the band hang in front of your thighs.', 'Paso 3: activa tus traps by shrugging tus hombros hacia arriba, lifting the band as high as possible.', 'Paso 4: Hold the contraction for a moment, then baja lentamente tus hombros back down to the posición inicial.', 'Paso 5: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'traps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
  gif_url     = EXCLUDED.gif_url,
  body_part   = EXCLUDED.body_part,
  equipment   = EXCLUDED.equipment,
  target_muscle    = EXCLUDED.target_muscle,
  secondary_muscles= EXCLUDED.secondary_muscles,
  instructions     = EXCLUDED.instructions,
  muscle_group_id  = EXCLUDED.muscle_group_id;

