  'Cable Incline Fly (On Stability Ball)',
  'https://static.exercisedb.dev/media/27NNGFr.gif',
  'chest',
  'cable',
  'pectorals',
  ARRAY['deltoids', 'triceps']::text[],
  ARRAY['Paso 1: Set up a stability ball at an incline angle.', 'Paso 2: Attach el cable handles to the high pulleys of a cable machine.', 'Paso 3: siéntate en the stability ball facing away from la máquina, with tus pies firmly planted on el suelo.', 'Paso 4: Grasp el cable handles with an overhand grip, palmas mirando hacia adelante.', 'Paso 5: Lean hacia adelante slightly, keeping tu espalda straight and core engaged.', 'Paso 6: With a controlled motion, bring tus brazos out to the sides, keeping a slight bend in your elbows.', 'Paso 7: Continue the motion until tus brazos are parallel to el suelo.', 'Paso 8: haz una pausa breve, then regresa lentamente to the posición inicial.', 'Paso 9: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'chest' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
