  'Kettlebell Double Alternating Hang Clean',
  'https://static.exercisedb.dev/media/a4F9Oyc.gif',
  'upper arms',
  'kettlebell',
  'biceps',
  ARRAY['forearms', 'shoulders']::text[],
  ARRAY['Paso 1: párate con los pies al ancho de los hombros, holding a kettlebell in each hand with an overhand grip.', 'Paso 2: dobla las rodillas slightly and hinge hacia adelante at the hips, keeping tu espalda straight and chest up.', 'Paso 3: Allow the kettlebells to hang straight down in front of tu cuerpo.', 'Paso 4: In one fluid motion, explosively extend tus caderas and knees while shrugging tus hombros.', 'Paso 5: As the kettlebells rise, pull them up towards tus hombros, keeping your elbows high and out to the sides.', 'Paso 6: Catch the kettlebells at shoulder height, with your palmas mirando hacia adentro and your elbows pointing hacia adelante.', 'Paso 7: Lower the kettlebells back down to the posición inicial and repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'biceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
