  'barbell clean and press',
  'Barbell Clean And Press',
  'https://static.exercisedb.dev/media/SGY8Zui.gif',
  'upper legs',
  'barbell',
  'quads',
  ARRAY['hamstrings', 'glutes', 'shoulders', 'triceps']::text[],
  ARRAY['Paso 1: párate con los pies al ancho de los hombros and la barra on el suelo in front of you.', 'Paso 2: dobla las rodillas and hinge at the hips to lower down and grip la barra with an overhand grip, hands slightly wider than al ancho de los hombros.', 'Paso 3: Drive through your heels and extend tus caderas and knees to lift la barra off el suelo, keeping it close to tu cuerpo.', 'Paso 4: As la barra reaches your thighs, explosively extend tus caderas, shrug tus hombros, and pull la barra up towards tu pecho.', 'Paso 5: As la barra reaches chest height, quickly drop under it and catch it at shoulder level, with your elbows pointing hacia adelante and your palmas mirando up.', 'Paso 6: From the catch position, press la barra sobre la cabeza by extending tus brazos and pushing la barra straight up.', 'Paso 7: Lower la barra back down to the posición inicial and repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'quadriceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
