  ARRAY['Paso 1: Start by lying on tu espalda with tus piernas extended and the kettlebell held in your right hand, arm fully extended above your shoulder.', 'Paso 2: Bend your right knee and place your right foot flat on el suelo, keeping your left leg extended.', 'Paso 3: Pressing through your right foot, levanta tus hips off el suelo, coming into a bridge position.', 'Paso 4: Slide your left leg underneath tu cuerpo, bending your left knee and placing your left foot flat on el suelo.', 'Paso 5: Rotate tu torso to the left, bringing your left hand to el suelo for support.', 'Paso 6: Pressing through your right foot and left hand, levanta tus torso off el suelo, coming into a kneeling position.', 'Paso 7: From the kneeling position, stand up, keeping the kettlebell extended sobre la cabeza.', 'Paso 8: Reverse the movement to return to the posición inicial.', 'Paso 9: Repeat the exercise on the other side, starting with the kettlebell in your left hand.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'glutes' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
  gif_url     = EXCLUDED.gif_url,
  body_part   = EXCLUDED.body_part,
  equipment   = EXCLUDED.equipment,
