  'https://static.exercisedb.dev/media/9pa4H5m.gif',
  'waist',
  'band',
  'abs',
  ARRAY['obliques', 'glutes']::text[],
  ARRAY['Paso 1: Attach the band to a sturdy anchor point at waist height.', 'Paso 2: Stand perpendicular to the anchor point with tus pies al ancho de los hombros.', 'Paso 3: Grasp the band handle with both hands and step away from the anchor point to create tension in the band.', 'Paso 4: Bring tus manos to tu pecho, keeping your elbows bent and close to tu cuerpo.', 'Paso 5: activa el core and maintain a stable stance.', 'Paso 6: Extend tus brazos straight out in front of you, pushing the band away from tu cuerpo.', 'Paso 7: Hold the extended position for a few seconds, focusing on maintaining tension in your core.', 'Paso 8: Slowly bring tus manos back to tu pecho, resisting the pull of the band.', 'Paso 9: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'abs' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
