  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'jK2hZ6n',
  'dumbbell one arm seated hammer curl',
  'Dumbbell One Arm Seated Hammer Curl',
  'https://static.exercisedb.dev/media/jK2hZ6n.gif',
  'upper arms',
  'dumbbell',
  'biceps',
  ARRAY['forearms']::text[],
  ARRAY['Paso 1: siéntate en a bench with tu espalda straight and feet flat on el suelo.', 'Paso 2: Hold a dumbbell in one hand with a neutral grip (palmas mirando each other).', 'Paso 3: Rest your elbow on the inside of your thigh, just above the knee.', 'Paso 4: Keeping your upper arm stationary, exhale and curl la mancuerna up towards your shoulder.', 'Paso 5: haz una pausa breve at the top, squeezing your biceps.', 'Paso 6: Inhale and baja lentamente la mancuerna back to the posición inicial.', 'Paso 7: repite por el número deseado de repeticiones, then switch arms.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'biceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
  gif_url     = EXCLUDED.gif_url,
  body_part   = EXCLUDED.body_part,
  equipment   = EXCLUDED.equipment,
  target_muscle    = EXCLUDED.target_muscle,
  secondary_muscles= EXCLUDED.secondary_muscles,
  instructions     = EXCLUDED.instructions,
  muscle_group_id  = EXCLUDED.muscle_group_id;

INSERT INTO exercises (
  exercisedb_id, name, name_es,
  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  '9sgNE2O',
  'barbell decline pullover',
  'Barbell Decline Pullover',
  'https://static.exercisedb.dev/media/9sgNE2O.gif',
  'chest',
  'barbell',
  'pectorals',
  ARRAY['triceps', 'shoulders']::text[],
  ARRAY['Paso 1: Lie down on a decline bench with tu cabeza lower than tus caderas and tus pies secured.', 'Paso 2: Hold la barra with a pronated grip (palmas mirando away from you) and tus manos slightly wider than al ancho de los hombros.', 'Paso 3: Extend tus brazos above tu pecho, keeping a slight bend in your elbows.', 'Paso 4: Lower la barra in an arc motion behind tu cabeza, feeling a stretch in tu pecho and shoulders.', 'Paso 5: haz una pausa breve, then return la barra to the posición inicial by reversing the motion.', 'Paso 6: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'chest' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
  gif_url     = EXCLUDED.gif_url,
  body_part   = EXCLUDED.body_part,
  equipment   = EXCLUDED.equipment,
