  'Assisted Lying Leg Raise With Lateral Throw Down',
  'https://static.exercisedb.dev/media/UGhRD1A.gif',
  'waist',
  'assisted',
  'abs',
  ARRAY['hip flexors', 'obliques']::text[],
  ARRAY['Paso 1: Lie flat on tu espalda with tus piernas extended and tus brazos by your sides.', 'Paso 2: Place tus manos under your glutes for support.', 'Paso 3: activa tus abs and levanta tus legs off el suelo, keeping them straight.', 'Paso 4: While keeping tus piernas together, lower them to one side until they are a few inches above el suelo.', 'Paso 5: haz una pausa breve, then levanta tus legs back to the posición inicial.', 'Paso 6: Repeat the movement to the other side.', 'Paso 7: Continue alternating sides for the desired number of repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'abs' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
