INSERT INTO exercises (
  exercisedb_id, name, name_es,
  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  '6pTkI99',
  'dumbbell one arm snatch',
  'Dumbbell One Arm Snatch',
  'https://static.exercisedb.dev/media/6pTkI99.gif',
  'upper legs',
  'dumbbell',
  'glutes',
  ARRAY['hamstrings', 'quadriceps', 'core']::text[],
  ARRAY['Paso 1: párate con los pies al ancho de los hombros, holding a dumbbell in one hand with an overhand grip.', 'Paso 2: dobla las rodillas slightly and hinge hacia adelante at the hips, keeping tu espalda straight and chest up.', 'Paso 3: Lower la mancuerna towards el suelo, keeping it close to tu cuerpo.', 'Paso 4: Explosively extend tus caderas, knees, and ankles, driving la mancuerna upwards in a straight line.', 'Paso 5: As la mancuerna reaches shoulder height, quickly rotate your hand and punch it sobre la cabeza, fully extending your arm.', 'Paso 6: Catch la mancuerna sobre la cabeza with a slight bend in tus rodillas and hips.', 'Paso 7: Lower la mancuerna back down to the posición inicial in a controlled manner.', 'Paso 8: repite por el número deseado de repeticiones, then switch to the other arm.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'glutes' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
