INSERT INTO exercises (
  exercisedb_id, name, name_es,
  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'PSlvNMs',
  'weighted drop push up',
  'Weighted Drop Push Up',
  'https://static.exercisedb.dev/media/PSlvNMs.gif',
  'chest',
  'weighted',
  'pectorals',
  ARRAY['triceps', 'shoulders']::text[],
  ARRAY['Paso 1: Start in a high plank position with tus manos slightly wider than al ancho de los hombros and tus pies together.', 'Paso 2: baja tus chest towards el suelo, keeping your elbows close to tu cuerpo.', 'Paso 3: Once tu pecho is just above el suelo, explosively push yourself up, lifting tus manos off el suelo.', 'Paso 4: As you push up, quickly move tus manos out to the sides and slightly hacia adelante, allowing tu cuerpo to drop down towards el suelo.', 'Paso 5: Catch yourself with tus manos in the wider position and immediately baja tus chest towards el suelo again.', 'Paso 6: Repeat the push-up motion, dropping down and catching yourself with tus manos in the narrower position.', 'Paso 7: Continue alternating between the wider and narrower hand positions for the desired number of repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'chest' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
