  'WCAvOfC',
  'side-to-side toe touch (male)',
  'Side-To-Side Toe Touch (Male)',
  'https://static.exercisedb.dev/media/WCAvOfC.gif',
  'waist',
  'body weight',
  'abs',
  ARRAY['obliques', 'hip flexors']::text[],
  ARRAY['Paso 1: párate con los pies al ancho de los hombros and tus brazos extended to the sides.', 'Paso 2: Bend at the waist to the right, reaching your right hand towards your right foot while keeping your left hand extended to the side.', 'Paso 3: Return to the posición inicial and then bend at the waist to the left, reaching your left hand towards your left foot while keeping your right hand extended to the side.', 'Paso 4: Repeat the side-to-side bending motion for the desired number of repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'abs' LIMIT 1)
