  'kettlebell',
  'delts',
  ARRAY['triceps', 'core']::text[],
  ARRAY['Paso 1: párate con los pies al ancho de los hombros, holding a kettlebell in one hand at shoulder height.', 'Paso 2: dobla las rodillas slightly and activa el core.', 'Paso 3: Press the kettlebell sobre la cabeza in a straight line, fully extending your arm.', 'Paso 4: As you press the kettlebell sobre la cabeza, simultaneously dip tus rodillas and quickly straighten them to generate momentum.', 'Paso 5: As the kettlebell reaches its highest point, quickly drop underneath it by bending tus rodillas and hips.', 'Paso 6: Catch the kettlebell with a slight bend in tus rodillas and hips, and your arm fully extended sobre la cabeza.', 'Paso 7: párate erguido, fully extending tus rodillas and hips, and stabilize the kettlebell sobre la cabeza.', 'Paso 8: Lower the kettlebell back to the posición inicial by bending tus rodillas and hips, and repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'shoulders' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
