  ARRAY['Paso 1: Start by kneeling on el suelo with tus manos al ancho de los hombros, dedos pointing hacia adelante.', 'Paso 2: Extend tus piernas behind you, resting on the balls of tus pies, so that tu cuerpo forms a straight line from head to heels.', 'Paso 3: activa el core and baja tus body towards el suelo by bending your elbows, keeping them close to your sides.', 'Paso 4: Continue lowering until tu pecho is just above el suelo, then push back up to the posición inicial by straightening tus brazos.', 'Paso 5: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'chest' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
