  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'xbkPfaw',
  'bodyweight standing one arm row',
  'Bodyweight Standing One Arm Row',
  'https://static.exercisedb.dev/media/xbkPfaw.gif',
  'back',
  'body weight',
  'upper back',
  ARRAY['biceps', 'forearms']::text[],
  ARRAY['Paso 1: párate con los pies al ancho de los hombros, knees slightly bent, and hold a dumbbell in one hand.', 'Paso 2: Bend hacia adelante at the hips, keeping tu espalda straight and your core engaged.', 'Paso 3: Let la mancuerna hang straight down in front of you, with your arm fully extended.', 'Paso 4: Pull la mancuerna up towards tu pecho, keeping your elbow close to tu cuerpo.', 'Paso 5: contrae tus shoulder blades together at the punto máximo del movimiento.', 'Paso 6: Lower la mancuerna back down to the posición inicial.', 'Paso 7: repite por el número deseado de repeticiones, then switch sides.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'back' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
  gif_url     = EXCLUDED.gif_url,
  body_part   = EXCLUDED.body_part,
  equipment   = EXCLUDED.equipment,
  target_muscle    = EXCLUDED.target_muscle,
  secondary_muscles= EXCLUDED.secondary_muscles,
  instructions     = EXCLUDED.instructions,
  muscle_group_id  = EXCLUDED.muscle_group_id;

