  'MUic5zN',
  'single arm push-up',
  'Single Arm Push-Up',
  'https://static.exercisedb.dev/media/MUic5zN.gif',
  'chest',
  'body weight',
  'pectorals',
  ARRAY['triceps', 'shoulders', 'core']::text[],
  ARRAY['Paso 1: Start in a push-up position with tus manos al ancho de los hombros and one hand placed slightly wider than the other.', 'Paso 2: activa el core and baja tus body towards el suelo by bending your elbows, keeping tu espalda straight.', 'Paso 3: As you lower yourself, shift your weight to one side and lift the opposite arm off el suelo, extending it straight out to the side.', 'Paso 4: Push through tu pecho and triceps to raise tu cuerpo back up to the posición inicial, while simultaneously lowering your extended arm back to el suelo.', 'Paso 5: Repeat the movement, alternating the arm you extend with each repetition.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'chest' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
