  'Exercise Ball Lower Back Stretch (Pyramid)',
  'https://static.exercisedb.dev/media/yU7w7CA.gif',
  'back',
  'stability ball',
  'lats',
  ARRAY['glutes', 'hamstrings']::text[],
  ARRAY['Paso 1: siéntate en the stability ball with tus pies flat on el suelo and tus rodillas bent at a 90-degree angle.', 'Paso 2: Slowly walk tus pies hacia adelante, rolling the ball down tu espalda until your lower back is resting on the ball.', 'Paso 3: Place tus manos behind tu cabeza or cross them over tu pecho.', 'Paso 4: activa el core and baja lentamente your upper body towards el suelo, allowing your lower back to stretch over the ball.', 'Paso 5: Hold the stretch for a few seconds, then regresa lentamente to the posición inicial.', 'Paso 6: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'lats' LIMIT 1)
