  ARRAY['Paso 1: Adjust the seat of the leverage machine so that tus hombros are aligned with the lever pad.', 'Paso 2: Place your toes on the lever pad, with your heels hanging off the edge.', 'Paso 3: Grasp the handles or side supports for stability.', 'Paso 4: Push the lever pad down by extending your ankles, contracting your calf muscles.', 'Paso 5: haz una pausa breve at the punto más bajo del movimiento.', 'Paso 6: regresa lentamente to the posición inicial by allowing your heels to rise back up.', 'Paso 7: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'calves' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
