  ARRAY['Paso 1: Lie flat on a bench with tu espalda and head supported, and tus pies flat on el suelo.', 'Paso 2: Hold a dumbbell in each hand with your palmas mirando up and your brazos completamente extendidos.', 'Paso 3: Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.', 'Paso 4: Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.', 'Paso 5: Hold the contracted position for a brief pause as you contrae tus biceps.', 'Paso 6: Inhale and slowly begin to lower the dumbbells back to the posición inicial.', 'Paso 7: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'biceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
