  ARRAY['Paso 1: párate erguido with tus pies al ancho de los hombros and hold the ez barbell with an underhand grip.', 'Paso 2: Keep your elbows close to tu torso and your upper arms stationary throughout the exercise.', 'Paso 3: Curl la barra upwards by contracting your biceps, while exhaling.', 'Paso 4: Continue to raise la barra until your biceps are fully contracted and la barra is at shoulder level.', 'Paso 5: Hold the contracted position for a brief pause as you contrae tus biceps.', 'Paso 6: Slowly begin to bring la barra back to the posición inicial as you inhale.', 'Paso 7: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'biceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
