  ARRAY['Paso 1: Lie flat on tu espalda with tus piernas extended and tus brazos by your sides.', 'Paso 2: dobla las rodillas and levanta tus legs off el suelo, bringing them towards tu pecho.', 'Paso 3: As you levanta tus legs, twist tus caderas to one side, bringing tus rodillas towards your opposite shoulder.', 'Paso 4: haz una pausa breve at the top, then baja lentamente tus piernas back down to the posición inicial.', 'Paso 5: Repeat the movement, this time twisting tus caderas to the other side.', 'Paso 6: Continue alternating sides for the desired number of repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'abs' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
