  'glutes',
  ARRAY['quadriceps', 'hamstrings', 'calves']::text[],
  ARRAY['Paso 1: Set up the smith machine with la barra at an appropriate height for your squat.', 'Paso 2: párate con los pies al ancho de los hombros, toes slightly turned out.', 'Paso 3: Position yourself under la barra, resting it on your upper traps and shoulders.', 'Paso 4: Grip la barra with a wide grip, slightly wider than al ancho de los hombros.', 'Paso 5: activa el core and unrack la barra, stepping back to clear the rack.', 'Paso 6: Keeping tu pecho up and back straight, initiate the squat by bending at the hips and knees.', 'Paso 7: baja tus body until your thighs are parallel to el suelo or slightly below.', 'Paso 8: haz una pausa breve at the bottom, then drive through your heels to return to the posición inicial.', 'Paso 9: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'glutes' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
