INSERT INTO exercises (
  exercisedb_id, name, name_es,
  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'dG5Smob',
  'snatch pull',
  'Snatch Pull',
  'https://static.exercisedb.dev/media/dG5Smob.gif',
  'upper legs',
  'barbell',
  'quads',
  ARRAY['hamstrings', 'glutes', 'calves']::text[],
  ARRAY['Paso 1: párate con los pies al ancho de los hombros and la barra on el suelo in front of you.', 'Paso 2: dobla las rodillas and hinge at the hips to lower into a squat position, gripping la barra with an overhand grip.', 'Paso 3: mantén la espalda recta and chest up as you drive through your heels to lift la barra off el suelo, extending tus caderas and knees.', 'Paso 4: As la barra reaches hip level, explosively pull it upwards, shrugging tus hombros and pulling your elbows high and to the sides.', 'Paso 5: As la barra reaches its highest point, quickly drop underneath it, pulling yourself into a deep squat position.', 'Paso 6: Catch la barra sobre la cabeza with your brazos completamente extendidos and tus rodillas bent.', 'Paso 7: Stand up by extending tus caderas and knees, keeping la barra sobre la cabeza.', 'Paso 8: Lower la barra back down to the posición inicial by reversing the movement.', 'Paso 9: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'quadriceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
