  ARRAY['Paso 1: siéntate en an exercise ball and hold a dumbbell in each hand.', 'Paso 2: Walk tus pies hacia adelante and roll tu cuerpo down until tu cabeza, neck, and upper back are supported by the ball.', 'Paso 3: Extend tus brazos straight up above tu pecho, palmas mirando each other.', 'Paso 4: Bend your elbows slightly and baja tus arms out to the sides in a wide arc until you feel a stretch in tu pecho.', 'Paso 5: haz una pausa breve, then reverse the movement and contrae tus chest muscles as you bring the dumbbells back to the posición inicial.', 'Paso 6: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'chest' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
