  'upper legs',
  'barbell',
  'quads',
  ARRAY['glutes', 'hamstrings', 'calves', 'core']::text[],
  ARRAY['Paso 1: Start with la barra resting on tus hombros, with tus pies al ancho de los hombros.', 'Paso 2: baja tus body into a squat position, keeping tu pecho up and tus rodillas tracking over your toes.', 'Paso 3: As you reach the bottom of the squat, explosively drive through tus piernas and push la barra sobre la cabeza.', 'Paso 4: As la barra reaches its peak, quickly drop into a split position, with one foot hacia adelante and one foot back.', 'Paso 5: Catch la barra sobre la cabeza with your brazos completamente extendidos and tu espalda knee slightly touching el suelo.', 'Paso 6: Stand up from the split position, bringing tus pies back together.', 'Paso 7: Lower la barra back to tus hombros and repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'quadriceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
