  ARRAY['Paso 1: párate erguido with a dumbbell in each hand, palmas mirando tu cuerpo.', 'Paso 2: Keep your elbows close to tu torso and your upper arms stationary.', 'Paso 3: Exhale and curl the weights while contracting your biceps, bringing the dumbbells across tu cuerpo towards your opposite shoulder.', 'Paso 4: Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.', 'Paso 5: Hold the contracted position for a brief pause as you contrae tus biceps.', 'Paso 6: Inhale and slowly begin to lower the dumbbells back to the posición inicial.', 'Paso 7: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'biceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
