  'pectorals',
  ARRAY['triceps', 'shoulders', 'core']::text[],
  ARRAY['Paso 1: siéntate en an exercise ball with tus pies flat on el suelo and la mancuerna resting on your thighs.', 'Paso 2: Slowly walk tus pies hacia adelante, rolling the exercise ball down tu espalda until tu cabeza, neck, and upper back are supported on the ball.', 'Paso 3: Hold la mancuerna with both hands and extend tus brazos straight up over tu pecho, keeping a slight bend in your elbows.', 'Paso 4: Lower la mancuerna behind tu cabeza, keeping tus brazos straight and maintaining control.', 'Paso 5: haz una pausa breve, then raise la mancuerna back to the posición inicial.', 'Paso 6: While keeping tus brazos extended, levanta tus hips off el suelo, squeezing your glutes and engaging your core.', 'Paso 7: baja tus hips back down to the posición inicial.', 'Paso 8: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'chest' LIMIT 1)
