  'back',
  'cable',
  'upper back',
  ARRAY['biceps', 'shoulders']::text[],
  ARRAY['Paso 1: Attach a v-bar attachment to a cable machine at chest height.', 'Paso 2: Stand facing el cable machine with tus pies al ancho de los hombros.', 'Paso 3: Grasp the v-bar with an overhand grip, palmas mirando down.', 'Paso 4: Take a step back to create tension in el cable.', 'Paso 5: mantén la espalda recta and core engaged throughout the exercise.', 'Paso 6: Pull the v-bar towards tu torso by retracting your shoulder blades and bending your elbows.', 'Paso 7: As you pull, twist tu torso to one side, squeezing your shoulder blades together.', 'Paso 8: haz una pausa breve at the punto máximo del movimiento, feeling the contraction in your upper back.', 'Paso 9: Slowly release the tension and return to the posición inicial, untwisting tu torso.', 'Paso 10: Repeat the movement for the desired number of repeticiones, alternating the twisting direction with each rep.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'back' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
