  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'IGtBdNT',
  'dumbbell seated hammer curl',
  'Dumbbell Seated Hammer Curl',
  'https://static.exercisedb.dev/media/IGtBdNT.gif',
  'upper arms',
  'dumbbell',
  'biceps',
  ARRAY['forearms']::text[],
  ARRAY['Paso 1: siéntate en a bench with a dumbbell in each hand, palmas mirando tu torso and arms extended straight down.', 'Paso 2: Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.', 'Paso 3: Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.', 'Paso 4: Hold the contracted position for a brief pause as you contrae tus biceps.', 'Paso 5: Inhale and slowly begin to lower the dumbbells back to the posición inicial.', 'Paso 6: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'biceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
  gif_url     = EXCLUDED.gif_url,
  body_part   = EXCLUDED.body_part,
  equipment   = EXCLUDED.equipment,
  target_muscle    = EXCLUDED.target_muscle,
  secondary_muscles= EXCLUDED.secondary_muscles,
