) VALUES (
  '225x2Vd',
  'band kneeling twisting crunch',
  'Band Kneeling Twisting Crunch',
  'https://static.exercisedb.dev/media/225x2Vd.gif',
  'waist',
  'band',
  'abs',
  ARRAY['obliques']::text[],
  ARRAY['Paso 1: Attach the band to a sturdy anchor point at waist height.', 'Paso 2: Kneel down facing away from the anchor point and hold the band with both hands, keeping your elbows bent and close to your sides.', 'Paso 3: activa tus abs and slowly twist tu torso to one side, bringing tus manos towards your opposite hip.', 'Paso 4: haz una pausa breve, then regresa lentamente to the posición inicial.', 'Paso 5: Repeat on the other side.', 'Paso 6: Continue alternating sides for the desired number of repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'abs' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
