) VALUES (
  'gFyFj9z',
  'dumbbell step-up lunge',
  'Dumbbell Step-Up Lunge',
  'https://static.exercisedb.dev/media/gFyFj9z.gif',
  'upper legs',
  'dumbbell',
  'quads',
  ARRAY['glutes', 'hamstrings', 'calves']::text[],
  ARRAY['Paso 1: Stand in front of a step or platform with a dumbbell in each hand, palmas mirando your sides.', 'Paso 2: Place your right foot on the step, ensuring your entire foot is on the surface.', 'Paso 3: Push through your right heel and levanta tus body up onto the step, bringing your left foot up as well.', 'Paso 4: Once both feet are on the step, baja tus left foot back down to the posición inicial, keeping your right foot on the step.', 'Paso 5: Repeat the movement, alternating which foot you step up with each time.', 'Paso 6: Continue for the desired number of repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'quadriceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
