  'qXTaZnJ',
  'barbell full squat',
  'Barbell Full Squat',
  'https://static.exercisedb.dev/media/qXTaZnJ.gif',
  'upper legs',
  'barbell',
  'glutes',
  ARRAY['quadriceps', 'hamstrings', 'calves', 'core']::text[],
  ARRAY['Paso 1: párate con los pies al ancho de los hombros, toes slightly turned out.', 'Paso 2: Hold la barra across your upper back, resting it on your traps or rear delts.', 'Paso 3: activa el core and keep tu pecho up as you begin to baja tus body down.', 'Paso 4: Bend at the knees and hips, pushing tus caderas back and down as if sitting into a chair.', 'Paso 5: Lower yourself until your thighs are parallel to el suelo or slightly below.', 'Paso 6: Keep tus rodillas in line with your toes and your weight in your heels.', 'Paso 7: Drive through your heels to stand back up, extending tus caderas and knees.', 'Paso 8: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'glutes' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
