INSERT INTO exercises (
  exercisedb_id, name, name_es,
  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'yUdIGNs',
  'cable rear delt row (stirrups)',
  'Cable Rear Delt Row (Stirrups)',
  'https://static.exercisedb.dev/media/yUdIGNs.gif',
  'shoulders',
  'cable',
  'delts',
  ARRAY['trapezius', 'rhomboids', 'biceps']::text[],
  ARRAY['Paso 1: Attach a stirrup handle to a low cable pulley and stand facing la máquina.', 'Paso 2: Grasp the handle with your left hand and take a step back with your right foot, positioning tu cuerpo at a slight angle.', 'Paso 3: dobla las rodillas slightly and hinge hacia adelante at the hips, keeping tu espalda straight and your core engaged.', 'Paso 4: With your left arm extended and your palm facing down, pull the handle towards tu pecho by retracting your shoulder blade.', 'Paso 5: haz una pausa breve at the punto máximo del movimiento, squeezing your shoulder blade.', 'Paso 6: Slowly release the handle back to the posición inicial and repite por el número deseado de repeticiones.', 'Paso 7: Switch sides and repeat the exercise with your right arm.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'shoulders' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
