  'kettlebell',
  'abs',
  ARRAY['shoulders', 'triceps', 'obliques']::text[],
  ARRAY['Paso 1: párate con los pies al ancho de los hombros, holding a kettlebell in your right hand.', 'Paso 2: dobla las rodillas slightly and press the kettlebell sobre la cabeza with your right arm, keeping your elbow locked.', 'Paso 3: Rotate tu torso to the left, shifting your weight onto your left foot.', 'Paso 4: Bend your left knee and baja tus torso towards el suelo, keeping your right arm extended sobre la cabeza.', 'Paso 5: As you lower, keep your eyes on the kettlebell and tu pecho lifted.', 'Paso 6: Once your left hand touches el suelo, push through your left foot and straighten your left leg, driving tus caderas hacia adelante.', 'Paso 7: As you drive tus caderas hacia adelante, use your core and right arm to press the kettlebell back up to the posición inicial.', 'Paso 8: repite por el número deseado de repeticiones, then switch sides.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'abs' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
