  'glutes',
  ARRAY['quadriceps', 'hamstrings', 'calves']::text[],
  ARRAY['Paso 1: Adjust la barra on the smith machine to an appropriate height for tu cuerpo.', 'Paso 2: párate con los pies al ancho de los hombros, toes slightly pointed outwards.', 'Paso 3: Position yourself under la barra, resting it on your upper traps and shoulders.', 'Paso 4: Grasp la barra with an overhand grip, slightly wider than al ancho de los hombros.', 'Paso 5: activa el core and keep tu pecho up as you unrack la barra.', 'Paso 6: Take a step back and position tus pies slightly wider than al ancho de los hombros.', 'Paso 7: dobla las rodillas and baja tus body down, keeping tu pecho up and back straight.', 'Paso 8: Continue descending until your thighs are parallel to el suelo or slightly below.', 'Paso 9: haz una pausa breve at the bottom, then push through your heels to return to the posición inicial.', 'Paso 10: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'glutes' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
