INSERT INTO exercises (
  exercisedb_id, name, name_es,
  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  '1VpF8db',
  'dumbbell bicep curl lunge with bowling motion',
  'Dumbbell Bicep Curl Lunge With Bowling Motion',
  'https://static.exercisedb.dev/media/1VpF8db.gif',
  'upper arms',
  'dumbbell',
  'biceps',
  ARRAY['forearms', 'shoulders']::text[],
  ARRAY['Paso 1: párate con los pies al ancho de los hombros, holding a dumbbell in each hand with your palmas mirando hacia adelante.', 'Paso 2: Take a step hacia adelante with your right foot, bending your right knee and lowering tu cuerpo into a lunge position.', 'Paso 3: As you lunge hacia adelante, curl the dumbbells up towards tus hombros, keeping your elbows close to tu cuerpo.', 'Paso 4: At the bottom of the lunge, rotate tu torso to the right, as if you were bowling a ball.', 'Paso 5: Reverse the motion, stepping back with your right foot and returning to the posición inicial while lowering the dumbbells back down.', 'Paso 6: Repeat the lunge and curl motion, this time rotating tu torso to the left.', 'Paso 7: Continue alternating sides for the desired number of repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'biceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
