  'stability ball',
  'hamstrings',
  ARRAY['glutes', 'lower back']::text[],
  ARRAY['Paso 1: siéntate en the stability ball with tus pies flat on el suelo and tus rodillas bent at a 90-degree angle.', 'Paso 2: Slowly roll the ball hacia adelante, walking tus pies out until your upper back is resting on the ball and tus piernas are extended straight in front of you.', 'Paso 3: Place tus manos on tus caderas for support.', 'Paso 4: activa el core and baja lentamente your upper body towards el suelo, keeping tu espalda straight and tu pecho lifted.', 'Paso 5: Stop when you feel a stretch in your hamstrings, and hold the position for 20-30 seconds.', 'Paso 6: regresa lentamente to the posición inicial by pushing through your heels and using your hamstrings to pull yourself back up.', 'Paso 7: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'hamstrings' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
