  'smith machine',
  'glutes',
  ARRAY['quadriceps', 'hamstrings', 'calves']::text[],
  ARRAY['Paso 1: Set up the smith machine with la barra at a height that allows you to comfortably rest it on your upper back.', 'Paso 2: párate con los pies al ancho de los hombros, toes slightly turned outwards.', 'Paso 3: Step under la barra and position it across your upper back, resting it on your traps.', 'Paso 4: Grip la barra with tus manos slightly wider than al ancho de los hombros.', 'Paso 5: Unrack la barra by straightening tus piernas and stepping back from the rack.', 'Paso 6: Take a deep breath and brace your core.', 'Paso 7: Initiate the squat by pushing tus caderas back and bending tus rodillas.', 'Paso 8: baja tus body until your thighs are parallel to el suelo or slightly below.', 'Paso 9: Keep tu pecho up and tu espalda straight throughout the movement.', 'Paso 10: Drive through your heels to stand back up, extending tus caderas and knees.', 'Paso 11: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'glutes' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
