  'push-up plus',
  'Push-Up Plus',
  'https://static.exercisedb.dev/media/pvBMLHA.gif',
  'chest',
  'body weight',
  'pectorals',
  ARRAY['triceps', 'shoulders']::text[],
  ARRAY['Paso 1: Start in a high plank position with tus manos slightly wider than al ancho de los hombros and tu cuerpo in a straight line from head to heels.', 'Paso 2: baja tus body towards el suelo by bending your elbows, keeping them close to your sides.', 'Paso 3: Once tu pecho is just above el suelo, push through tus manos to extend tus brazos and levanta tus upper body up.', 'Paso 4: At the punto máximo del movimiento, protract your shoulder blades by pushing your upper back towards the ceiling.', 'Paso 5: haz una pausa breve, then reverse the movement by retracting your shoulder blades and lowering tu cuerpo back down to the posición inicial.', 'Paso 6: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'chest' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
