  '0JtKWum',
  'dumbbell burpee',
  'Burpee con mancuerna',
  'https://static.exercisedb.dev/media/0JtKWum.gif',
  'cardio',
  'dumbbell',
  'cardiovascular system',
  ARRAY['quadriceps', 'hamstrings', 'calves', 'shoulders', 'triceps', 'core']::text[],
  ARRAY['Paso 1: Start in a standing position with tus pies al ancho de los hombros and a dumbbell in each hand.', 'Paso 2: baja tus body into a squat position, placing the dumbbells on el suelo in front of you.', 'Paso 3: Kick tus pies back into a push-up position, keeping tu cuerpo in a straight line.', 'Paso 4: Perform a push-up, bending your elbows and lowering tu pecho towards el suelo.', 'Paso 5: Jump tus pies back towards tus manos, landing in a squat position.', 'Paso 6: Stand up explosively, lifting the dumbbells off el suelo and bringing them to tus hombros.', 'Paso 7: Press the dumbbells sobre la cabeza, fully extending tus brazos.', 'Paso 8: Lower the dumbbells back to tus hombros and repeat the entire sequence for the desired number of repeticiones.']::text[],
  false,
  NULL
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
