  '7jGOBF3',
  'dumbbell close grip press',
  'Dumbbell Close Grip Press',
  'https://static.exercisedb.dev/media/7jGOBF3.gif',
  'upper arms',
  'dumbbell',
  'triceps',
  ARRAY['chest', 'shoulders']::text[],
  ARRAY['Paso 1: siéntate en a flat bench with a dumbbell in each hand, resting on your thighs.', 'Paso 2: Using your thighs to help raise the dumbbells, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width.', 'Paso 3: Once at shoulder width, rotate your wrists hacia adelante so that the palms of tus manos are facing away from you. This will be your posición inicial.', 'Paso 4: As you breathe in, baja lentamente the dumbbells to your side until they are about level with tu pecho.', 'Paso 5: As you exhale, use your triceps to lift the dumbbells back to the posición inicial. Make sure to use only your triceps and do not use your forearms or biceps to help lift the dumbbells.', 'Paso 6: After a second pause at the contracted position, repeat the movement for the prescribed amount of repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'triceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
