  'back',
  'body weight',
  'traps',
  ARRAY['biceps', 'rhomboids', 'rear deltoids']::text[],
  ARRAY['Paso 1: Start by hanging from una barra de dominadas with your palmas mirando away from you and your brazos completamente extendidos.', 'Paso 2: Retract your shoulder blades by pulling them down and back.', 'Paso 3: activa tus back muscles and pull tu cuerpo up towards la barra, focusing on squeezing your shoulder blades together.', 'Paso 4: haz una pausa breve at the punto máximo del movimiento, then baja lentamente tu cuerpo back down to the posición inicial.', 'Paso 5: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'traps' LIMIT 1)
