  'Power Clean',
  'https://static.exercisedb.dev/media/SiWCcTN.gif',
  'upper legs',
  'barbell',
  'hamstrings',
  ARRAY['glutes', 'quadriceps', 'calves']::text[],
  ARRAY['Paso 1: Start with la barra on el suelo in front of you, with tus pies al ancho de los hombros.', 'Paso 2: Bend down and grip la barra with an overhand grip, slightly wider than al ancho de los hombros.', 'Paso 3: mantén la espalda recta and chest up as you lift la barra off el suelo, extending tus caderas and knees.', 'Paso 4: As la barra reaches your mid-thigh, explosively pull it upwards, shrugging tus hombros and pulling your elbows high and to the sides.', 'Paso 5: As la barra reaches its highest point, quickly drop underneath it, rotating your elbows around and catching la barra on tus hombros in a front squat position.', 'Paso 6: Stand up with la barra, fully extending tus caderas and knees.', 'Paso 7: Lower la barra back down to the posición inicial, keeping control of the weight throughout the movement.', 'Paso 8: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'hamstrings' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
