  'Pike-To-Cobra Push-Up',
  'https://static.exercisedb.dev/media/XPUDTt7.gif',
  'upper legs',
  'body weight',
  'glutes',
  ARRAY['core', 'shoulders', 'triceps']::text[],
  ARRAY['Paso 1: Start in a push-up position with tus manos slightly wider than al ancho de los hombros and tus pies together.', 'Paso 2: activa el core and levanta tus hips up towards the ceiling, forming an inverted V shape with tu cuerpo.', 'Paso 3: baja tus upper body towards el suelo by bending your elbows, keeping them close to tu cuerpo.', 'Paso 4: As you lower down, shift your weight hacia adelante and transition into a cobra pose by straightening tus brazos and lifting tu pecho up.', 'Paso 5: Reverse the movement by bending your elbows and lowering tu pecho back down towards el suelo.', 'Paso 6: Push through tus manos to return to the inverted V position.', 'Paso 7: Continue the movement by lowering tus caderas back down towards el suelo, returning to the starting push-up position.', 'Paso 8: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'glutes' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
