  'kettlebell',
  'forearms',
  ARRAY['shoulders', 'traps', 'core']::text[],
  ARRAY['Paso 1: párate con los pies al ancho de los hombros, holding a kettlebell in each hand with an overhand grip.', 'Paso 2: dobla las rodillas slightly and hinge hacia adelante at the hips, keeping tu espalda straight and chest up.', 'Paso 3: Allow the kettlebells to hang in front of tu cuerpo with your brazos completamente extendidos.', 'Paso 4: In one fluid motion, explosively extend tus caderas, shrug tus hombros, and pull the kettlebells up towards tus hombros.', 'Paso 5: As the kettlebells reach shoulder height, rotate your wrists and catch the kettlebells in the rack position, with your palmas mirando hacia adentro and the kettlebells resting on the outside of your forearms.', 'Paso 6: Lower the kettlebells back down to the posición inicial and repeat the movement with the opposite arm.', 'Paso 7: Continue alternating arms for the desired number of repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'forearms' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
