  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'xTjr103',
  'standing hamstring and calf stretch with strap',
  'Standing Hamstring And Calf Stretch With Strap',
  'https://static.exercisedb.dev/media/xTjr103.gif',
  'upper legs',
  'rope',
  'hamstrings',
  ARRAY['calves']::text[],
  ARRAY['Paso 1: Stand upright with tus pies al ancho de los hombros.', 'Paso 2: Hold the strap with both hands and place it around the ball of your foot.', 'Paso 3: Keep your leg straight and slowly lean hacia adelante from tus caderas, keeping tu espalda straight.', 'Paso 4: Feel the stretch in your hamstring and calf muscles.', 'Paso 5: Hold the stretch for 20-30 seconds.', 'Paso 6: Release the stretch and repeat with the other leg.', 'Paso 7: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'hamstrings' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
  gif_url     = EXCLUDED.gif_url,
  body_part   = EXCLUDED.body_part,
  equipment   = EXCLUDED.equipment,
  target_muscle    = EXCLUDED.target_muscle,
  secondary_muscles= EXCLUDED.secondary_muscles,
  instructions     = EXCLUDED.instructions,
  muscle_group_id  = EXCLUDED.muscle_group_id;

