  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  '8gQo5Ss',
  'single style cable standing crunch (with rope attachment)',
  'Single Style Cable Standing Crunch (With Rope Attachment)',
  'https://static.exercisedb.dev/media/8gQo5Ss.gif',
  'waist',
  'cable',
  'abs',
  ARRAY['obliques']::text[],
  ARRAY['Paso 1: Attach a rope to a cable machine at chest height.', 'Paso 2: Stand facing away from la máquina with tus pies al ancho de los hombros. Focus on single movement.', 'Paso 3: Hold the rope with both hands and bring it behind tu cabeza, keeping your elbows bent.', 'Paso 4: activa tus abs and slowly crunch tu torso hacia adelante, bringing your elbows towards tus rodillas.', 'Paso 5: haz una pausa breve at the top of the crunch, then regresa lentamente to the posición inicial.', 'Paso 6: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'abs' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
  gif_url     = EXCLUDED.gif_url,
  body_part   = EXCLUDED.body_part,
  equipment   = EXCLUDED.equipment,
  target_muscle    = EXCLUDED.target_muscle,
  secondary_muscles= EXCLUDED.secondary_muscles,
  instructions     = EXCLUDED.instructions,
  muscle_group_id  = EXCLUDED.muscle_group_id;

INSERT INTO exercises (
  exercisedb_id, name, name_es,
  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'PKlXuJW',
  'rough band push sit-up',
  'Rough Band Push Sit-Up',
  'https://static.exercisedb.dev/media/PKlXuJW.gif',
  'waist',
  'band',
  'abs',
  ARRAY['shoulders', 'chest']::text[],
  ARRAY['Paso 1: Attach the band securely to a stable anchor point.', 'Paso 2: Lie flat on tu espalda with tus rodillas bent and feet flat on el suelo.', 'Paso 3: Hold the band with both hands and extend tus brazos straight up towards the ceiling. Focus on rough movement.', 'Paso 4: Engaging your abs, slowly levanta tus upper body off el suelo, curling hacia adelante until tu torso is at a 45-degree angle.', 'Paso 5: haz una pausa breve at the top, then baja lentamente your upper body back down to the posición inicial.', 'Paso 6: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'abs' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
