  'Qj0HRAZ',
  'fast style resistance band seated hip abduction',
  'Fast Style Resistance Band Seated Hip Abduction',
  'https://static.exercisedb.dev/media/Qj0HRAZ.gif',
  'upper legs',
  'resistance band',
  'abductors',
  ARRAY['glutes', 'hamstrings']::text[],
  ARRAY['Paso 1: siéntate en a chair or bench with tu espalda straight and feet flat on el suelo.', 'Paso 2: Wrap the resistance band around your thighs, just above tus rodillas.', 'Paso 3: Place tus manos on the sides of the chair or bench for support.', 'Paso 4: (fast variation) activa tus abductors (outer thigh muscles) and slowly push tus rodillas apart, against the resistance of the band.', 'Paso 5: haz una pausa breve at the end of the movement, then slowly bring tus rodillas back together.', 'Paso 6: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'glutes' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
