INSERT INTO exercises (
  exercisedb_id, name, name_es,
  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'Um8xUAc',
  'barbell prone incline curl with intensive',
  'Barbell Prone Incline Curl With Intensive',
  'https://static.exercisedb.dev/media/Um8xUAc.gif',
  'upper arms',
  'barbell',
  'biceps',
  ARRAY['forearms']::text[],
  ARRAY['Paso 1: Set up an incline bench at a 45-degree angle.', 'Paso 2: acuéstate boca abajo on el banco with tu pecho and stomach resting against it.', 'Paso 3: Hold a barbell with an underhand grip, al ancho de los hombros.', 'Paso 4: Extend tus brazos fully, allowing la barra to hang down towards el suelo.', 'Paso 5: Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.', 'Paso 6: Continue to raise la barra until your biceps are fully contracted and la barra is at shoulder level.', 'Paso 7: (intensive variation) Hold the contracted position for a brief pause as you contrae tus biceps.', 'Paso 8: Inhale and slowly begin to lower la barra back to the posición inicial.', 'Paso 9: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'biceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
  gif_url     = EXCLUDED.gif_url,
  body_part   = EXCLUDED.body_part,
  equipment   = EXCLUDED.equipment,
  target_muscle    = EXCLUDED.target_muscle,
  secondary_muscles= EXCLUDED.secondary_muscles,
  instructions     = EXCLUDED.instructions,
  muscle_group_id  = EXCLUDED.muscle_group_id;

INSERT INTO exercises (
