  'AdxxqfF',
  'barbell standing reverse grip curl resistance',
  'Barbell Standing Reverse Grip Curl Resistance',
  'https://static.exercisedb.dev/media/AdxxqfF.gif',
  'upper arms',
  'barbell',
  'biceps',
  ARRAY['forearms']::text[],
  ARRAY['Paso 1: párate erguido with tus pies al ancho de los hombros and hold a barbell with an underhand grip, palmas mirando up.', 'Paso 2: Keep your elbows close to tu torso and your upper arms stationary.', 'Paso 3: Exhale and curl the weights while contracting your biceps, bringing la barra as close to tus hombros as possible.', 'Paso 4: Hold the contracted position for a brief pause as you contrae tus biceps.', 'Paso 5: Inhale and baja lentamente la barra back to the posición inicial.', 'Paso 6: repite por el número deseado de repeticiones. Focus on resistance movement.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'biceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
