  'hjWjJEm',
  'exercise ball hip flexor stretch pointed',
  'Exercise Ball Hip Flexor Stretch Pointed',
  'https://static.exercisedb.dev/media/hjWjJEm.gif',
  'upper legs',
  'stability ball',
  'glutes',
  ARRAY['quadriceps', 'hamstrings']::text[],
  ARRAY['Paso 1: Place the stability ball on el suelo and kneel in front of it.', 'Paso 2: Place your right foot on top of the stability ball, with your knee bent at a 90-degree angle.', 'Paso 3: Extend your left leg behind you, keeping it straight.', 'Paso 4: Lean hacia adelante, pushing tus caderas towards the stability ball, until you feel a stretch in your right hip flexor.', 'Paso 5: Hold the stretch for 20-30 seconds, then switch sides and repeat. Emphasize pointed control.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'glutes' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
