INSERT INTO exercises (
  exercisedb_id, name, name_es,
  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'XE93sQZ',
  'dumbbell step up single leg balance with bicep curl - chair variation',
  'Dumbbell Step Up Single Leg Balance With Bicep Curl - Chair Variation',
  'https://static.exercisedb.dev/media/XE93sQZ.gif',
  'upper arms',
  'dumbbell',
  'biceps',
  ARRAY['quadriceps', 'glutes', 'hamstrings']::text[],
  ARRAY['Paso 1: Stand in front of a step or platform with a dumbbell in each hand, palmas mirando tu cuerpo.', 'Paso 2: Place your right foot on the step, ensuring your entire foot is in contact with the surface.', 'Paso 3: activa el core and push through your right heel to levanta tus body up onto the step, bringing your left knee up towards tu pecho.', 'Paso 4: At the punto máximo del movimiento, perform a bicep curl by bending your elbows and bringing the dumbbells towards tus hombros.', 'Paso 5: Lower the dumbbells back down and simultaneously baja tus left foot back to el suelo.', 'Paso 6: (chair variation) Repeat the movement on the opposite side, stepping up with your left foot and curling the dumbbells.', 'Paso 7: Continue alternating sides for the desired number of repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'biceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
  name_es     = EXCLUDED.name_es,
  gif_url     = EXCLUDED.gif_url,
