INSERT INTO exercises (
  exercisedb_id, name, name_es,
  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'pgIdT6i',
  'band one arm standing low row - lateral variation',
  'Band One Arm Standing Low Row - Lateral Variation',
  'https://static.exercisedb.dev/media/pgIdT6i.gif',
  'back',
  'band',
  'upper back',
  ARRAY['biceps', 'shoulders']::text[],
  ARRAY['Paso 1: Attach the band to a stable anchor point at waist height.', 'Paso 2: Stand facing the anchor point with tus pies al ancho de los hombros.', 'Paso 3: Hold the band with one hand, palm facing hacia adentro, and step back to create tension in the band.', 'Paso 4: dobla las rodillas slightly and hinge hacia adelante at the hips, keeping tu espalda straight.', 'Paso 5: Pull the band towards your waist, squeezing your shoulder blades together.', 'Paso 6: haz una pausa breve at the punto máximo del movimiento, then slowly release the band back to the posición inicial.', 'Paso 7: repite por el número deseado de repeticiones, then switch sides. Emphasize lateral control.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'back' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
