  ARRAY['Paso 1: Start by kneeling on el suelo with tus rodillas al ancho de las caderas and your toes pointing hacia adelante.', 'Paso 2: Place a barbell across tus hombros, gripping it with an overhand grip and tus manos slightly wider than al ancho de los hombros.', 'Paso 3: activa el core and keep tu pecho lifted as you baja lentamente tu cuerpo down by bending tus rodillas, keeping tu espalda straight. Perform with pure intensity.', 'Paso 4: Continue lowering until your thighs are parallel to el suelo, or as low as you can comfortably go.', 'Paso 5: haz una pausa breve at the bottom, then push through your heels to return to the posición inicial.', 'Paso 6: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'quadriceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name        = EXCLUDED.name,
