-- ============================================================
-- Vista helper: labels en español para UI
-- ============================================================

CREATE OR REPLACE VIEW exercises_es AS
SELECT
  e.*,
  CASE e.body_part
    WHEN 'back' THEN 'espalda'
    WHEN 'cardio' THEN 'cardio'
    WHEN 'chest' THEN 'pecho'
    WHEN 'lower arms' THEN 'antebrazos'
    WHEN 'lower legs' THEN 'pantorrillas'
    WHEN 'neck' THEN 'cuello'
    WHEN 'shoulders' THEN 'hombros'
    WHEN 'upper arms' THEN 'brazos'
    WHEN 'upper legs' THEN 'piernas'
    WHEN 'waist' THEN 'cintura / core'
    ELSE e.body_part
  END AS body_part_es,
  CASE e.equipment
    WHEN 'assisted' THEN 'asistido'
    WHEN 'band' THEN 'banda elástica'
    WHEN 'barbell' THEN 'barra'
    WHEN 'body weight' THEN 'peso corporal'
    WHEN 'cable' THEN 'polea / cable'
    WHEN 'dumbbell' THEN 'mancuerna'
    WHEN 'ez barbell' THEN 'barra EZ'
    WHEN 'hammer' THEN 'martillo'
    WHEN 'kettlebell' THEN 'kettlebell'
    WHEN 'leverage machine' THEN 'máquina de palanca'
    WHEN 'medicine ball' THEN 'balón medicinal'
    WHEN 'olympic barbell' THEN 'barra olímpica'
    WHEN 'resistance band' THEN 'banda de resistencia'
    WHEN 'roller' THEN 'rodillo / foam roller'
    WHEN 'rope' THEN 'cuerda'
    WHEN 'skierg machine' THEN 'máquina ski erg'
    WHEN 'sled machine' THEN 'trineo / sled'
    WHEN 'smith machine' THEN 'máquina Smith'
    WHEN 'stability ball' THEN 'balón de estabilidad'
    WHEN 'stationary bike' THEN 'bicicleta estática'
    WHEN 'stepmill machine' THEN 'escaladora'
    WHEN 'tire' THEN 'llanta / neumático'
    WHEN 'trap bar' THEN 'barra trap'
    WHEN 'upper body ergometer' THEN 'ergómetro de tren superior'
    WHEN 'weighted' THEN 'con peso libre'
    WHEN 'wheel roller' THEN 'rueda abdominal'
    ELSE e.equipment
  END AS equipment_es,
  CASE e.target_muscle
    WHEN 'abs' THEN 'abdominales'
    WHEN 'abductors' THEN 'abductores'
    WHEN 'adductors' THEN 'aductores'
    WHEN 'biceps' THEN 'bíceps'
    WHEN 'calves' THEN 'pantorrillas'
    WHEN 'cardiovascular system' THEN 'sistema cardiovascular'
    WHEN 'delts' THEN 'deltoides'
    WHEN 'forearms' THEN 'antebrazos'
    WHEN 'glutes' THEN 'glúteos'
    WHEN 'hamstrings' THEN 'isquiotibiales'
    WHEN 'hip flexors' THEN 'flexores de cadera'
    WHEN 'lats' THEN 'dorsales'
    WHEN 'levator scapulae' THEN 'elevador de la escápula'
    WHEN 'obliques' THEN 'oblicuos'
    WHEN 'pectorals' THEN 'pectorales'
    WHEN 'quads' THEN 'cuádriceps'
    WHEN 'serratus anterior' THEN 'serrato anterior'
    WHEN 'spine' THEN 'columna / erectores'
    WHEN 'traps' THEN 'trapecios'
    WHEN 'triceps' THEN 'tríceps'
    WHEN 'upper back' THEN 'espalda alta'
    ELSE e.target_muscle
  END AS target_muscle_es
FROM exercises e
WHERE e.is_custom = false;

